+    // Wait up to 10 seconds for Chrome to print debug URL (profiles can be slow)
+    const timeout_ns = 10 * std.time.ns_per_s;
+    const start_time = std.time.nanoTimestamp();
+
+    while (std.time.nanoTimestamp() - start_time < timeout_ns) {
