+        .{ .ext = ".json", .mime = "application/json" },
+        .{ .ext = ".xml", .mime = "application/xml" },
+        .{ .ext = ".txt", .mime = "text/plain" },
+        .{ .ext = ".md", .mime = "text/markdown" },
+        .{ .ext = ".png", .mime = "image/png" },
+        .{ .ext = ".jpg", .mime = "image/jpeg" },
+        .{ .ext = ".jpeg", .mime = "image/jpeg" },
+        .{ .ext = ".gif", .mime = "image/gif" },
